noncompliant:
// Noncompliant: Variable declared before if statement
int result = get_value();
if (result > 0) {
    process(result);
} else {
    handle_error();
}
// 'result' is still in scope here
some_other_function();

// Noncompliant: Variable scope extends beyond switch
auto status = get_status();
switch (status) {
    case Status::OK:
        handle_ok();
        break;
    case Status::ERROR:
        handle_error();
        break;
}
// 'status' unnecessarily available here

compliant:
// Compliant: if with initializer (C++17)
if (int result = get_value(); result > 0) {
    process(result);
} else {
    handle_error();
}
// 'result' is out of scope here
some_other_function();

// Compliant: switch with initializer (C++17)
switch (auto status = get_status(); status) {
    case Status::OK:
        handle_ok();
        break;
    case Status::ERROR:
        handle_error();
        break;
}
// 'status' is out of scope here
